import React, { useCallback, useMemo, useState } from 'react';
import {
  dispatchAppToast,
  LIN_ERP_LIST_FILTER_LAYOUT,
  LinErpListFilterBar,
  LinPageLayout,
  LinReportPrintScopeModal,
  LinReportTableConfigModal,
  fetchReportPagesInBatches,
  loadErpReportDisplayConfig,
  resolveReportCharts,
  saveErpReportDisplayConfig,
  useServerPagedListLoading,
  ListGridBusyWrap,
  Pagination,
  type ErpReportDisplayConfig,
  type ReportPrintScope,
} from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { analyticsService } from '../../../services/analytics/analyticsService';
import { formatDate, formatVnd } from '../../../utils/formatters';
import { monthStartEnd } from '../../../utils/exportExcel';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import {
  buildReportChartQueryParams,
  isReportChartsEnabled,
  isReportChartConfigChanged,
  mapReportChartCatalog,
  normalizeJournalLedgerReport,
} from '../../../utils/buildReportChartQueryParams';
import erp from '../../../styles/erpPage.module.css';
import reportStyles from '../../../styles/erpReportPage.module.css';
import type { JournalLedgerReport } from '../../../services/analytics/models';

const TEST_ID = 'erp-nhat-ky-chung-tu';
const PAGE_ID = 'baocao-nhat-ky-chung-tu';

const NKCT_DEFAULT_PAGE_SIZE = 20;

const labels = {
  title: 'Nhật ký chứng từ',
  listTitle: 'Chi tiết phát sinh',
  empty: 'Chọn khoảng thời gian và bấm Xem',
  loadError: 'Lỗi tải Nhật ký chứng từ',
  printLoadError: 'Lỗi tải dữ liệu in',
  stt: 'STT',
  sttAriaLabel: 'Số thứ tự',
  voucherDate: 'Ngày CT',
  voucherCode: 'Số CT',
  description: 'Diễn giải',
  debitAccount: 'TK Nợ',
  creditAccount: 'TK Có',
  debitAmount: 'Số tiền Nợ',
  creditAmount: 'Số tiền Có',
  headerTotalDebit: 'Tổng PS Nợ',
  headerTotalCredit: 'Tổng PS Có',
  headerEntryCount: 'Số dòng',
  // Config modal labels
  configModalTitle: 'Sửa config — Nhật ký chứng từ',
  configSectionGrid: 'Bảng dữ liệu',
  configSectionFooter: 'Footer',
  configSectionPrint: 'In báo cáo',
  configPrintBatchSizeLabel: 'Số dòng mỗi lần tải (in tất cả trang)',
  configPrintBatchSizeHint: 'Từ 50 đến 500 — mặc định 200.',
  configSectionChart: 'Biểu đồ',
  configChartEmptyHint: 'Chưa có dữ liệu biểu đồ.',
  // Print modal labels
  printModalTitle: 'In Nhật ký chứng từ',
  printScopeLabel: 'Phạm vi in',
  printCurrentPageOption: 'Trang hiện tại ({count} dòng)',
  printAllPagesOption: 'Tất cả các trang ({total} dòng)',
  printCancel: 'Hủy',
  printConfirm: 'In',
  printFetchHint: 'In tất cả trang sẽ tải dữ liệu từ server theo lô.',
  // Chart labels
  chartTitle: 'Biểu đồ Nhật ký chứng từ',
  chartNoTypes: 'Chưa có loại biểu đồ nào được chọn.',
  chartEmpty: 'Chưa có dữ liệu biểu đồ.',
};

function formatPrintScopeTemplate(template: string, vars: Record<string, string | number>): string {
  return template.replace(/\{(\w+)\}/g, (_, key: string) => String(vars[key] ?? ''));
}

const NhatKyChungTuPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { fromDate: iF, toDate: iT } = monthStartEnd();

  const [fromDate, setFromDate] = useState(iF);
  const [toDate, setToDate] = useState(iT);
  const [items, setItems] = useState<JournalLedgerReport['items']>([]);
  const [page, setPage] = useState(1);
  const [totalCount, setTotalCount] = useState(0);
  const [pageSize, setPageSize] = useState(NKCT_DEFAULT_PAGE_SIZE);
  const [allowedCharts, setAllowedCharts] = useState<JournalLedgerReport['charts']>([]);
  const [reportChartData, setReportChartData] = useState<unknown>(null);
  const [appliedFromDate, setAppliedFromDate] = useState<string | undefined>();
  const [appliedToDate, setAppliedToDate] = useState<string | undefined>();

  const {
    filterLoading,
    pageLoading,
    showTableLoading,
    setLoadingMode,
    beginFetch,
    endFetch,
  } = useServerPagedListLoading();

  const [configOpen, setConfigOpen] = useState(false);
  const [printModalOpen, setPrintModalOpen] = useState(false);
  const [printLoading, setPrintLoading] = useState(false);
  const [printAllPageItems, setPrintAllPageItems] = useState<JournalLedgerReport['items'] | null>(null);
  const [displayConfig, setDisplayConfig] = useState<ErpReportDisplayConfig>(() =>
    loadErpReportDisplayConfig(TEST_ID),
  );

  const gridPageSize = useMemo(
    () => (displayConfig.showFooterPagination && pageSize > 0 ? pageSize : Math.max(items.length, 1)),
    [displayConfig.showFooterPagination, pageSize, items.length],
  );

  const showAllPagesPrintOption = useMemo(
    () =>
      displayConfig.showFooterPagination
      && pageSize > 0
      && totalCount > items.length,
    [displayConfig.showFooterPagination, pageSize, totalCount, items.length],
  );

  const gridItems = printAllPageItems ?? items;
  const gridSttPage = printAllPageItems ? 1 : page;
  const gridSttPageSize = printAllPageItems ? Math.max(printAllPageItems.length, 1) : gridPageSize;

  const fetchReportWithConfig = useCallback(
    (
      targetPage: number,
      filters: { fromDate?: string; toDate?: string },
      config: ErpReportDisplayConfig,
      chartCatalog: JournalLedgerReport['charts'],
      loadingMode: 'filter' | 'page' = 'filter',
    ) => {
      const reqPageSize = config.showFooterPagination ? pageSize : 0;
      const chartQuery = buildReportChartQueryParams(config, chartCatalog);
      setLoadingMode(loadingMode === 'page' ? 'page' : 'filter');
      beginFetch();
      return analyticsService
        .getJournalLedger({
          fromDate: filters.fromDate,
          toDate: filters.toDate,
          page: targetPage,
          pageSize: reqPageSize,
          ...chartQuery,
        })
        .then((raw) => {
          const report = normalizeJournalLedgerReport(raw);
          setItems(report.items);
          setAllowedCharts(report.charts);
          setReportChartData(report.chartData);
          setTotalCount(report.totalCount);
          setPage(report.page);
          return report;
        })
        .catch((err: Error) => {
          dispatchAppToast(dispatch, { message: getApiErrorMessage(err, labels.loadError), type: 'error' });
          throw err;
        })
        .finally(() => {
          endFetch();
        });
    },
    [dispatch, pageSize, setLoadingMode, beginFetch, endFetch],
  );

  const handleLoad = useCallback(() => {
    setPage(1);
    setPrintAllPageItems(null);
    fetchReportWithConfig(1, { fromDate, toDate }, displayConfig, [])
      .then(() => {
        setAppliedFromDate(fromDate);
        setAppliedToDate(toDate);
      })
      .catch(() => undefined);
  }, [fromDate, toDate, displayConfig, fetchReportWithConfig]);

  const handlePageChange = useCallback(
    (nextPage: number) => {
      if (!appliedFromDate || pageLoading || nextPage < 1) return;
      setPage(nextPage);
      fetchReportWithConfig(nextPage, { fromDate: appliedFromDate, toDate: appliedToDate }, displayConfig, allowedCharts, 'page').catch(() => undefined);
    },
    [appliedFromDate, appliedToDate, pageLoading, displayConfig, allowedCharts, fetchReportWithConfig],
  );

  const handlePrint = useCallback(() => {
    if (totalCount === 0 || showTableLoading || printLoading) return;
    setPrintModalOpen(true);
  }, [totalCount, showTableLoading, printLoading]);

  const handlePrintScopeConfirm = useCallback(
    async (scope: ReportPrintScope) => {
      if (!appliedFromDate || showTableLoading) return;
      setPrintLoading(true);
      try {
        if (scope === 'allPages') {
          const rowsForPrint = await fetchReportPagesInBatches<JournalLedgerReport['items'][number]>({
            totalCount,
            batchSize: displayConfig.printFetchBatchSize,
            fetchPage: async (targetPage, batchSize) => {
              const raw = await analyticsService.getJournalLedger({
                fromDate: appliedFromDate,
                toDate: appliedToDate,
                page: targetPage,
                pageSize: batchSize,
                includeChartData: false,
              });
              return normalizeJournalLedgerReport(raw).items;
            },
          });
          setPrintAllPageItems(rowsForPrint);
          setTimeout(() => {
            window.print();
            setPrintAllPageItems(null);
          }, 100);
        } else {
          setPrintAllPageItems(null);
          setTimeout(() => {
            window.print();
          }, 100);
        }
        setPrintModalOpen(false);
      } catch (err) {
        dispatchAppToast(dispatch, {
          message: getApiErrorMessage(err, labels.printLoadError),
          type: 'error',
        });
      } finally {
        setPrintLoading(false);
      }
    },
    [
      appliedFromDate,
      appliedToDate,
      showTableLoading,
      totalCount,
      displayConfig.printFetchBatchSize,
      dispatch,
    ],
  );

  const visibleCharts = useMemo(() => {
    const catalog = mapReportChartCatalog(allowedCharts);
    if (!isReportChartsEnabled(displayConfig.chart, allowedCharts)) return [];
    return resolveReportCharts(catalog, displayConfig.chart);
  }, [allowedCharts, displayConfig.chart]);

  const canShowCharts = totalCount > 0 && visibleCharts.length > 0 && reportChartData != null;

  const handleOpenChart = useCallback(() => {
    if (totalCount === 0 || !reportChartData) return;
    if (visibleCharts.length === 0) {
      dispatchAppToast(dispatch, { message: labels.chartNoTypes, type: 'info' });
      return;
    }
    dispatchAppToast(dispatch, { message: 'Biểu đồ — đang phát triển', type: 'info' });
  }, [totalCount, reportChartData, visibleCharts.length, dispatch]);

  const handleSaveDisplayConfig = (next: ErpReportDisplayConfig) => {
    const chartChanged = isReportChartConfigChanged(displayConfig.chart, next.chart);
    const paginationChanged = next.showFooterPagination !== displayConfig.showFooterPagination;
    setDisplayConfig(next);
    saveErpReportDisplayConfig(TEST_ID, next);
    if ((paginationChanged || chartChanged) && appliedFromDate) {
      setPage(1);
      setPrintAllPageItems(null);
      fetchReportWithConfig(1, { fromDate: appliedFromDate, toDate: appliedToDate }, next, allowedCharts).catch(() => undefined);
    }
  };

  const hasData = appliedFromDate != null && totalCount > 0;
  const canPrint = hasData && !showTableLoading && !printLoading && !pageLoading;

  const reportFilters = useMemo(
    () => (
      <LinErpListFilterBar
        testIdPrefix={TEST_ID}
        fromDate={fromDate}
        toDate={toDate}
        onDateChange={(from, to) => {
          setFromDate(from ?? '');
          setToDate(to ?? '');
        }}
        dateLabel="Thời gian"
        expandDateRangeAriaLabel="Thêm ngày kết thúc"
        onSearch={handleLoad}
        searchAriaLabel="Xem"
        loading={filterLoading}
      />
    ),
    [fromDate, toDate, handleLoad, filterLoading],
  );

  const totalPages = useMemo(
    () => (gridPageSize > 0 ? Math.ceil(totalCount / gridPageSize) : 1),
    [totalCount, gridPageSize],
  );

  const reportToolbar = useMemo(
    () => ({
      testIdPrefix: TEST_ID,
      onRefresh: handleLoad,
      canChart: canShowCharts,
      onChart: handleOpenChart,
      canPrint,
      onPrint: handlePrint,
      onEditConfig: () => setConfigOpen(true),
    }),
    [handleLoad, canShowCharts, handleOpenChart, handlePrint, canPrint],
  );

  const summaryBar = hasData ? (
    <div className={reportStyles.summaryBar}>
      <div className={reportStyles.summaryItem}>
        <label>{labels.headerTotalDebit}</label>
        <strong>{formatVnd(items.reduce((s, r) => s + r.debitAmount, 0))}</strong>
      </div>
      <div className={reportStyles.summaryItem}>
        <label>{labels.headerTotalCredit}</label>
        <strong>{formatVnd(items.reduce((s, r) => s + r.creditAmount, 0))}</strong>
      </div>
      <div className={reportStyles.summaryItem}>
        <label>{labels.headerEntryCount}</label>
        <strong>{totalCount.toLocaleString('vi-VN')}</strong>
      </div>
    </div>
  ) : null;

  const listBody = !showTableLoading && totalCount === 0 ? (
    <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>{labels.empty}</div>
  ) : !showTableLoading ? (
    <>
      {summaryBar}
      <ListGridBusyWrap pageLoading={pageLoading}>
        <div className={reportStyles.tableCard}>
          <div className={reportStyles.tableWrapper}>
            <table className={reportStyles.table} data-testid={`${TEST_ID}-grid`}>
              <thead>
                <tr>
                  <th className={reportStyles.colStt} aria-label={labels.sttAriaLabel}>{labels.stt}</th>
                  <th>{labels.voucherDate}</th>
                  <th>{labels.voucherCode}</th>
                  <th>{labels.description}</th>
                  <th>{labels.debitAccount}</th>
                  <th>{labels.creditAccount}</th>
                  <th className={reportStyles.colRight}>{labels.debitAmount}</th>
                  <th className={reportStyles.colRight}>{labels.creditAmount}</th>
                </tr>
              </thead>
              <tbody>
                {gridItems.map((r, i) => (
                  <tr key={r.voucherCode + r.debitAccountCode + r.creditAccountCode + i}>
                    <td className={reportStyles.colStt}>
                      {(gridSttPage - 1) * gridSttPageSize + i + 1}
                    </td>
                    <td>{formatDate(r.voucherDate)}</td>
                    <td>{r.voucherCode}</td>
                    <td>{r.description ?? '—'}</td>
                    <td>{r.debitAccountName ? `${r.debitAccountCode} - ${r.debitAccountName}` : r.debitAccountCode}</td>
                    <td>{r.creditAccountName ? `${r.creditAccountCode} - ${r.creditAccountName}` : r.creditAccountCode}</td>
                    <td className={reportStyles.colRight}>{formatVnd(r.debitAmount)}</td>
                    <td className={reportStyles.colRight}>{formatVnd(r.creditAmount)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </ListGridBusyWrap>
    </>
  ) : null;

  return (
    <div
      className={erp.voucherListRoot}
      data-voucher-list-page
      data-catalog-list-page
      data-report-list-page
      data-testid={`${TEST_ID}-list`}
    >
      <LinPageLayout
        kind="report"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={erp.catalogListPage}
        listLayoutVariant="erp-filter-bar"
        listHeaderClassName={LIN_ERP_LIST_FILTER_LAYOUT.header}
        listFiltersClassName={LIN_ERP_LIST_FILTER_LAYOUT.filtersHost}
        header={{
          title: labels.title,
          titleIconClass: 'fas fa-book',
          pageId: PAGE_ID,
        }}
        reportToolbar={reportToolbar}
        listTitle={labels.listTitle}
        filters={reportFilters}
        filterBarLayout="standard"
        showTableLoading={showTableLoading}
        pageLoading={pageLoading}
        skeletonRows={8}
        footer={
          displayConfig.showFooterPagination && totalCount > 0 && gridPageSize > 0 ? (
            <Pagination
              currentPage={page}
              totalPages={totalPages}
              totalCount={totalCount}
              pageSize={gridPageSize}
              onPageChange={handlePageChange}
            />
          ) : undefined
        }
        modals={(
          <>
            <LinReportTableConfigModal
              isOpen={configOpen}
              onClose={() => setConfigOpen(false)}
              testIdPrefix={TEST_ID}
              config={displayConfig}
              chartCatalog={mapReportChartCatalog(allowedCharts)}
              onSave={handleSaveDisplayConfig}
              title={labels.configModalTitle}
              sectionGridLabel={labels.configSectionGrid}
              sectionFooterLabel={labels.configSectionFooter}
              sectionPrintLabel={labels.configSectionPrint}
              printBatchSizeLabel={labels.configPrintBatchSizeLabel}
              printBatchSizeHint={labels.configPrintBatchSizeHint}
              sectionChartLabel={labels.configSectionChart}
              chartEmptyHint={labels.configChartEmptyHint}
            />
            <LinReportPrintScopeModal
              isOpen={printModalOpen}
              onClose={() => !printLoading && setPrintModalOpen(false)}
              onConfirm={handlePrintScopeConfirm}
              printing={printLoading}
              testIdPrefix={TEST_ID}
              currentPage={page}
              currentPageRowCount={items.length}
              totalCount={totalCount}
              showAllPagesOption={showAllPagesPrintOption}
              labels={{
                title: labels.printModalTitle,
                scopeLabel: labels.printScopeLabel,
                currentPageOption: labels.printCurrentPageOption,
                allPagesOption: labels.printAllPagesOption,
                cancel: labels.printCancel,
                confirm: labels.printConfirm,
                fetchHint: labels.printFetchHint,
              }}
            />
          </>
        )}
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default NhatKyChungTuPage;
